starterCode.javascript:
// Define a function to calculate the total margin and padding of a CSS selector
function calculateMarginAndPadding(cssSelector) {
  // Use the css module to parse the input string and extract the margin and padding values
  const { margin, padding } = cssSelector;
  // Calculate the total margin and padding by summing up the individual values
  const totalMargin = margin + padding;
  const totalPadding = padding + padding;
  return `margin: ${totalMargin}, padding: ${totalPadding}`;
}

